<template><el-card><template #header><b>{{title}}</b></template><el-form label-width="120px" style="max-width:650px"><el-form-item v-if="mode==='first'" label="流动登记ID"><el-input-number v-model="form.floatingId" :min="1"/></el-form-item><el-form-item label="居住依据"><el-select v-model="form.residenceBasisCode"><el-option v-for="x in ['EMPLOYMENT','STUDY','FAMILY','BUSINESS','OTHER_APPROVED']" :key="x" :value="x"/></el-select></el-form-item><el-form-item label="标题"><el-input v-model="form.title"/></el-form-item><el-form-item label="原因"><el-input v-model="form.reason" type="textarea"/></el-form-item><el-form-item><el-button type="primary" @click="save">创建申请</el-button></el-form-item></el-form></el-card></template>
<script setup>import{reactive,computed}from'vue';import{useRoute,useRouter}from'vue-router';import{ElMessage}from'element-plus';import{firstIssue,endorseApplication,cancelApplication}from'../../api/floatingResidence';const route=useRoute(),router=useRouter(),mode=route.meta.mode||'first',form=reactive({floatingId:Number(route.query.floatingId)||null,residenceBasisCode:'EMPLOYMENT',title:mode==='first'?'居住证首次申领':mode==='endorse'?'居住证签注申请':'居住证注销申请',reason:'',remark:''}),title=computed(()=>form.title);async function save(){const r=mode==='first'?await firstIssue(form):mode==='endorse'?await endorseApplication(route.params.permitId,form):await cancelApplication(route.params.permitId,form);ElMessage.success('申请已创建');router.push('/residence-permits/applications/'+r.applicationId)}</script>
